public class VendorServiceHelper {
    public static List<Service__c> getAllServices(){
        List<Service__c> retServices = [
            SELECT Id, Name, LastModifiedDate, CreatedById, OwnerId
            FROM Service__c
            ORDER BY Name
        ];
        return retServices;
    }
}

public static Service__c getServiceById(Id serviceId){
    Service__c retService = [SELECT Id, Name FROM Service__c WHERE Id = :serviceId LIMIT 1];

    return retService;
}


public static Service__c getServiceByName(String serviceName){
    Service__c retService = [SELECT Id, Name FROM Service__c WHERE Name = :serviceName LIMIT 1];

    return retService;
}

public static void createVendorServicesForSingleVendor(Id vendorAcctId, Set<Id> serviceIds){

    List<Vendor_Service__c> vendorServices = new List<Vendor_Service__c>();

    for(Id serviceId : serviceIds){
        Vendor_Service__c newVendorService = new Vendor_Service__c();
        newVendorService.Vendor__c = vendorAcctId;
        newVendorService.Service__c = serviceId;
        vendorServices.add(newVendorService);
    }

    insert vendorServices;
}

public static void createVendorServicesForSingleService(Set<Id> vendorAcctIds, Id serviceId){

    List<Vendor_Service__c> vendorServices = new List<Vendor_Service__c>();

    for(Id acctId : vendorAcctIds){
        Vendor_Service__c newVendorService = new Vendor_Service__c();
        newVendorService.Vendor__c = acctId;
        newVendorService.Service__c = serviceId;

        vendorServices.add(newVendorService);
    }

    insert vendorServices;
}

public static String generateVendorServiceName(String vendorName, String serviceName){
    return vendorName + ' - ' + serviceName;
}

public class InvocableServiceFetcher {

    @InvocableMethod
    public static List<List<Service__c>> fetchServices(){
        List<List<Service__c>> retServices = new List<List<Service__c>>();

        List<Service__c> allServices = VendorServiceHelper.getAllServices();

        retServices.add(allServices);

        return retServices;
    }



}

public class InvocableVendorServiceBuilder {

    @InvocableMethod
    public static void createVendorWithServices(List<FlowVendorServiceParams> vendorServiceParams){

        FlowVendorServiceParams params = vendorServiceParams[0];
        Set<Id> serviceIdSet = new Set<Id>();
        serviceIdSet.addAll(params.serviceIds);

        vendorServiceHelper.createVendorServicesForSingleVendor(params.acctId, serviceIdSet);
    }

    public class FlowVendorServiceParams{
        @InvocableVariable public Id acctId;
        @InvocableVariable public List<Id> serviceIds;
    }
}

public class UnitTriggerHandler {
    public static void afterUpdate(List<Unit__c> newUnits, Map<Id, Unit__c> oldMap) {
        for (Unit__c u : newUnits) {
            Unit__c old = oldMap.get(u.Id);
            if (u.OwnerContact__c != old.OwnerContact__c) {
                System.debug('Owner changed on ' + u.Id);
            }
        }
    }
}
